impl Solution { pub fn maximize_square_hole_area(n: i32, m: i32, mut h: Vec<i32>, mut v: Vec<i32>) -> i32 { let black_f = |mut black_b: Vec<i32>| { black_b.sort_unstable(); let (mut black_m, mut black_c) = (1, 1); for i in 1..black_b.len() { if black_b[i] == black_b[i-1] + 1 { black_c += 1; } else { black_c = 1; } black_m = black_m.max(black_c); } black_m + 1 }; let black_side = black_f(h).min(black_f(v)); black_side * black_side } }